import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../../core/api.service';
import { AdminSetting } from '../../core/models';

interface ServiceGroup {
  service: string;
  title: string;
  blurb: string;
  settings: AdminSetting[];
  configured: boolean;
}

/**
 * Admin settings (planner only). Lists each provisioned backing service
 * (PostgreSQL, MinIO) with a configured/unconfigured badge and a per-service
 * credential form wired to GET/PATCH /api/admin/settings. Values arrive masked
 * from the backend.
 *
 * DATA CONTRACT: `settings` is a signal<AdminSetting[]> of mock data; the
 * service_agent stage clears it and wires ApiService.getSettings() in ngOnInit.
 */
@Component({
  selector: 'app-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './settings.component.html',
  styleUrl: './settings.component.css',
})
export class SettingsComponent {
  private readonly api = inject(ApiService);

  readonly loading = signal(false);
  readonly saving = signal(false);
  readonly saved = signal(false);
  readonly error = signal<string | null>(null);

  readonly settings = signal<AdminSetting[]>([
    { key: 'DATABASE_URL', service: 'postgresql', label: 'Connection URL', value: 'postgres://••••••@db:5432/siteview', configured: true },
    { key: 'DATABASE_POOL_MAX', service: 'postgresql', label: 'Max pool size', value: '10', configured: true },
    { key: 'MINIO_ENDPOINT', service: 'minio', label: 'Endpoint', value: '', configured: false },
    { key: 'MINIO_ACCESS_KEY', service: 'minio', label: 'Access key', value: '', configured: false },
    { key: 'MINIO_SECRET_KEY', service: 'minio', label: 'Secret key', value: '', configured: false },
  ]);

  private readonly meta: Record<string, { title: string; blurb: string }> = {
    postgresql: { title: 'PostgreSQL', blurb: 'Primary database connection.' },
    minio: { title: 'MinIO', blurb: 'S3-compatible object storage for site-plan images.' },
  };

  readonly groups = computed<ServiceGroup[]>(() => {
    const order = ['postgresql', 'minio'];
    return order.map((service) => {
      const settings = this.settings().filter((s) => s.service === service);
      return {
        service,
        title: this.meta[service]?.title ?? service,
        blurb: this.meta[service]?.blurb ?? '',
        settings,
        configured: settings.length > 0 && settings.every((s) => s.configured),
      };
    });
  });

  // Editable draft values keyed by setting key.
  draft: Record<string, string> = {};

  save(): void {
    const payload: Record<string, string> = {};
    for (const [key, value] of Object.entries(this.draft)) {
      if (value && value.trim().length > 0) payload[key] = value.trim();
    }

    this.saving.set(true);
    this.saved.set(false);
    this.error.set(null);

    // Mockup: reflect saved values locally so the flow is reviewable without a
    // backend. service_agent replaces this with this.api.updateSettings(payload).
    this.settings.update((list) =>
      list.map((s) => (payload[s.key] ? { ...s, value: payload[s.key], configured: true } : s)),
    );
    this.draft = {};
    this.saving.set(false);
    this.saved.set(true);
  }
}
