import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../environments/environment';
import {
  AdminSetting,
  BudgetLine,
  Dashboard,
  Marker,
  Milestone,
  Phase,
  Project,
  SitePlan,
  Task,
  User,
} from './models';

/**
 * SiteView API client. Typed against models.ts and the surface contract
 * (global prefix api/v1). Reads are open to viewer + planner; writes are
 * planner-only (enforced server-side).
 *
 * The mockup feature components render local signal mock data; the
 * service_agent stage wires these methods into components via ngOnInit().
 */
@Injectable({ providedIn: 'root' })
export class ApiService {
  private readonly base = environment.apiUrl;

  constructor(private http: HttpClient) {}

  // ---- Users ----
  me(): Observable<User> {
    return this.http.get<User>(`${this.base}/users/me`);
  }

  // ---- Projects ----
  listProjects(status?: string): Observable<Project[]> {
    let params = new HttpParams();
    if (status) params = params.set('status', status);
    return this.http.get<Project[]>(`${this.base}/projects`, { params });
  }
  getProject(id: string): Observable<Project> {
    return this.http.get<Project>(`${this.base}/projects/${id}`);
  }
  createProject(body: Partial<Project>): Observable<Project> {
    return this.http.post<Project>(`${this.base}/projects`, body);
  }
  updateProject(id: string, body: Partial<Project>): Observable<Project> {
    return this.http.patch<Project>(`${this.base}/projects/${id}`, body);
  }
  deleteProject(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/projects/${id}`);
  }

  // ---- Phases (nested under project) ----
  listPhases(projectId: string): Observable<Phase[]> {
    return this.http.get<Phase[]>(`${this.base}/projects/${projectId}/phases`);
  }
  createPhase(projectId: string, body: Partial<Phase>): Observable<Phase> {
    return this.http.post<Phase>(`${this.base}/projects/${projectId}/phases`, body);
  }
  updatePhase(phaseId: string, body: Partial<Phase>): Observable<Phase> {
    return this.http.patch<Phase>(`${this.base}/phases/${phaseId}`, body);
  }
  deletePhase(phaseId: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/phases/${phaseId}`);
  }

  // ---- Tasks ----
  listTasks(projectId?: string): Observable<Task[]> {
    let params = new HttpParams();
    if (projectId) params = params.set('projectId', projectId);
    return this.http.get<Task[]>(`${this.base}/tasks`, { params });
  }
  getTask(id: string): Observable<Task> {
    return this.http.get<Task>(`${this.base}/tasks/${id}`);
  }
  createTask(body: Partial<Task>): Observable<Task> {
    return this.http.post<Task>(`${this.base}/tasks`, body);
  }
  updateTask(id: string, body: Partial<Task>): Observable<Task> {
    return this.http.patch<Task>(`${this.base}/tasks/${id}`, body);
  }
  updateTaskProgress(id: string, progressPct: number): Observable<Task> {
    return this.http.patch<Task>(`${this.base}/tasks/${id}/progress`, { progressPct });
  }
  deleteTask(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/tasks/${id}`);
  }

  // ---- Milestones ----
  listMilestones(projectId?: string): Observable<Milestone[]> {
    let params = new HttpParams();
    if (projectId) params = params.set('projectId', projectId);
    return this.http.get<Milestone[]>(`${this.base}/milestones`, { params });
  }
  createMilestone(body: Partial<Milestone>): Observable<Milestone> {
    return this.http.post<Milestone>(`${this.base}/milestones`, body);
  }
  updateMilestone(id: string, body: Partial<Milestone>): Observable<Milestone> {
    return this.http.patch<Milestone>(`${this.base}/milestones/${id}`, body);
  }
  deleteMilestone(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/milestones/${id}`);
  }

  // ---- Budget (BudgetLine per phase) ----
  listBudget(phaseId: string): Observable<BudgetLine[]> {
    return this.http.get<BudgetLine[]>(`${this.base}/phases/${phaseId}/budget`);
  }
  createBudgetLine(phaseId: string, body: Partial<BudgetLine>): Observable<BudgetLine> {
    return this.http.post<BudgetLine>(`${this.base}/phases/${phaseId}/budget`, body);
  }
  updateBudgetLine(id: string, body: Partial<BudgetLine>): Observable<BudgetLine> {
    return this.http.patch<BudgetLine>(`${this.base}/budget/${id}`, body);
  }
  deleteBudgetLine(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/budget/${id}`);
  }

  // ---- Site plan + markers ----
  getSitePlan(projectId: string): Observable<SitePlan> {
    return this.http.get<SitePlan>(`${this.base}/projects/${projectId}/siteplan`);
  }
  updateSitePlan(id: string, body: Partial<SitePlan>): Observable<SitePlan> {
    return this.http.patch<SitePlan>(`${this.base}/siteplan/${id}`, body);
  }
  createMarker(planId: string, body: Partial<Marker>): Observable<Marker> {
    return this.http.post<Marker>(`${this.base}/siteplan/${planId}/markers`, body);
  }
  updateMarker(id: string, body: Partial<Marker>): Observable<Marker> {
    return this.http.patch<Marker>(`${this.base}/markers/${id}`, body);
  }
  deleteMarker(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/markers/${id}`);
  }

  // ---- Dashboard ----
  getDashboard(projectId: string): Observable<Dashboard> {
    return this.http.get<Dashboard>(`${this.base}/dashboard/${projectId}`);
  }

  // ---- Admin settings (planner) ----
  getSettings(): Observable<AdminSetting[]> {
    return this.http.get<AdminSetting[]>(`${this.base}/admin/settings`);
  }
  updateSettings(body: Record<string, string>): Observable<AdminSetting[]> {
    return this.http.patch<AdminSetting[]>(`${this.base}/admin/settings`, body);
  }
}
